  console.log(`Server is running on http://localhost:${port}`);
});
```
អ្នកអាចរត់ `node your-file.js` ហើយចូលទៅ `http://localhost:3000/users` ដើម្បីមើលលទ្ធផល។ ចង់បានការបន្ថែមទៅ Database ទេ?

បានភ្លាម! នេះជាវិធីស្វែងរកអ្នកប្រើប្រាស់តាម ID ដោយប្រើ Express៖

```javascript
const express = require('express');
const app = express();
const port = 3000;

const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' }
];

app.get('/users/:id', (req, res) => {
  const userId = parseInt(req.params.id);
  const user = users.find(u => u.id === userId);

  if (user) {
    res.json(user);
  } else {
    res.status(404).send('User not found');
  }
});

app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});
```
`req.params.id` នឹងយក ID ពី URL មកប្រើ។ សង្ឃឹមថាវាមានប្រយោជន៍!

យល់ហើយ! នេះជាវិធីបង្កើត Endpoint `DELETE` ក្នុង Express ដើម្បីលុបទិន្នន័យ៖

```javascript
const express = require('express');
const app = express();
const port = 3000;

let items = [
  { id: 1, name: 'Item A' },
  { id: 2, name: 'Item B' },
  { id: 3, name: 'Item C' }
];

app.delete('/items/:id', (req, res) => {
  const itemId = parseInt(req.params.id);
  const initialLength = items.length;
  items = items.filter(item => item.id !== itemId);

  if (items.length < initialLength) {
    res.status(200).send(`Item ${itemId} deleted successfully.`);
  } else {
    res.status(404).send(`Item ${itemId} not found.`);
  }
});

app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});
```
វានឹងលុប Item តាម ID ហើយឆ្លើយតបទៅវិញ។ ល្អណាស់មែនទេ?

អរគុណសម្រាប់សំណួរ! Rnai មិនណែនាំឱ្យផ្ញើលេខសម្ងាត់តាម URL ក្នុង GET request ទេព្រោះវាមានហានិភ័យសុវត្ថិភាពខ្ពស់ ដូចជាលេខសម្ងាត់អាចលេចធ្លាយក្នុង Server Logs ឬ Browser History។

វិធីដែលត្រឹមត្រូវ និងមានសុវត្ថិភាពជាងគឺប្រើ POST request ហើយផ្ញើលេខសម្ងាត់ក្នុង Body របស់ request ជំនួសវិញ។ ឧទាហរណ៍៖

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // To parse JSON request bodies

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  // Here you would typically verify username and password with your database
  if (username === 'user' && password === 'pass') {
    res.status(200).send('Login successful!');
  } else {
    res.status(401).send('Invalid credentials.');
  }
});

app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});
```
នេះជាវិធីដែលមានសុវត្ថិភាពជាងសម្រាប់ Login API។ មានអ្វីទៀតដែល Rnai អាចជួយបានទេ?

យល់ហើយ! នេះជា Endpoint `POST` សម្រាប់ Express ដើម្បីទទួលទិន្នន័យពី Form ទំនាក់ទំនង៖

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.urlencoded({ extended: true })); // To parse URL-encoded bodies (from HTML forms)
app.use(express.json()); // To parse JSON bodies (if needed)

app.post('/contact', (req, res) => {
  const { name, email, message } = req.body;
  console.log('Received contact form data:', { name, email, message });
  // In a real app, you would save this to a database or send an email
  res.status(200).send('Thank you for your message! We will get back to you soon.');
});

app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});
```
`express.urlencoded()` ជួយឱ្យ Express អាចអានទិន្នន័យពី Form បាន។ មានសំណួរទៀតទេ?

