Chắc chắn rồi, đây là endpoint POST dùng Express để thêm người dùng, có parse body JSON:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // Để parse body JSON

app.post('/api/nguoi-dung', (req, res) => {
  const { ten, email } = req.body;
  if (!ten || !email) {
    return res.status(400).send('Tên và email là bắt buộc.');
  }
  // Trong thực tế, bạn sẽ lưu vào CSDL ở đây
  const nguoiDungMoi = { id: Date.now(), ten, email };
  res.status(201).json(nguoiDungMoi);
