function checkUserAccessClean(User $user, string $resource) {
    if (!$user->isAuthenticated()) {
        return false;
    }
    if (!$user->hasPermission($resource)) {
        return false;
    }
    if ($user->isSuspended()) {
        return false;
    }
    return true;
}
