แน่นอนครับ นี่คือฟังก์ชัน JavaScript ที่ใช้ `Intl.NumberFormat` เพื่อจัดรูปแบบตัวเลขเป็นสกุลเงินบาทไทย:

```javascript
function formatCurrencyTHB(amount) {
  return new Intl.NumberFormat('th-TH', {
    style: 'currency',
    currency: 'THB',
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  }).format(amount);
}

// ตัวอย่างการใช้งาน
console.log(`1234.56 บาท: ${formatCurrencyTHB(1234.56)}`); // 1,234.56 ฿
console.log(`98765.1 บาท: ${formatCurrencyTHB(98765.1)}`); // 98,765.10 ฿
console.log(`500 บาท: ${formatCurrencyTHB(500)}`); // 500.00 ฿
```
ฟังก์ชันนี้จะแสดงสัญลักษณ์สกุลเงิน '฿' และเพิ่มคอมม่าให้อัตโนมัติครับ

แน่นอนครับ วิธีที่ง่ายและนิยมที่สุดคือใช้ `Set` ครับ:

```javascript
function removeDuplicates(arr) {
  return [...new Set(arr)];
}

// ตัวอย่างการใช้งาน
const numbers = [1, 2, 2, 3, 4, 4, 5];
const uniqueNumbers = removeDuplicates(numbers);
console.log(`อาร์เรย์เดิม: [${numbers}]`); // [1,2,2,3,4,4,5]
console.log(`อาร์เรย์ที่ลบค่าซ้ำแล้ว: [${uniqueNumbers}]`); // [1,2,3,4,5]

const mixed = ['apple', 'banana', 'apple', 'orange'];
console.log(`อาร์เรย์ String: [${removeDuplicates(mixed)}]`); // [apple,banana,orange]
```
วิธีนี้ใช้ได้กับทั้งตัวเลขและข้อความเลยครับ

ได้เลยครับ นี่คือฟังก์ชัน JavaScript ง่ายๆ สำหรับแปลงหน่วยอุณหภูมิครับ:

```javascript
function celsiusToFahrenheit(celsius) {
  return (celsius * 9 / 5) + 32;
}

// ตัวอย่างการใช้งาน
console.log(`0°C คือ ${celsiusToFahrenheit(0)}°F`);   // 32°F
console.log(`25°C คือ ${celsiusToFahrenheit(25)}°F`);  // 77°F
console.log(`100°C คือ ${celsiusToFahrenheit(100)}°F`); // 212°F
```
คุณสามารถเรียกใช้ฟังก์ชันนี้ได้เลยครับ หากต้องการแปลงกลับก็สามารถแจ้งได้ครับ

