Sige, narito ang isang Python script na gumagamit ng `json` module para gawin iyan:

```python
import json

def extract_user_info(filepath: str) -> list[dict]:
    user_data = []
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            data = json.load(f)
            for entry in data:
                if 'name' in entry and 'email' in entry:
                    user_data.append({"name": entry['name'], "email": entry['email']})
    except FileNotFoundError:
        print(f"Error: File not found at {filepath}")
    except json.JSONDecodeError:
        print(f"Error: Invalid JSON format in {filepath}")
    return user_data

if __name__ == "__main__":
    # Halimbawa ng paggamit (siguraduhing may 'users.json' file ka)
    # users.json content: [{ "name": "Juan", "email": "juan@example.com" }, { "name": "Maria", "email": "maria@example.com" }]
    info = extract_user_info("users.json")
    for user in info:
        print(user)
```
