Narito ang simpleng Python script na magfa-filter ng mga linya na may salitang 'error' mula sa isang text file, linya por linya, para hindi maubos ang memorya:

```python
def filter_log_for_errors(filepath: str):
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            for line_num, line in enumerate(f, 1):
                if "error" in line.lower(): # Case-insensitive search
                    print(f"Line {line_num}: {line.strip()}")
    except FileNotFoundError:
        print(f"Error: File not found at {filepath}")

if __name__ == "__main__":
    filter_log_for_errors("app.log") # Palitan ang 'app.log' ng pangalan ng iyong file
```
