Tentu, ini fungsi JavaScript untuk memeriksa kekuatan password Anda:

```javascript
function checkPasswordStrength(password) {
  const minLength = 8;
  const hasUpperCase = /[A-Z]/.test(password);
  const hasLowerCase = /[a-z]/.test(password);
  const hasNumber = /[0-9]/.test(password);

  if (password.length < minLength) {
    return 'Password terlalu pendek (minimal 8 karakter).';
  }
  if (!hasUpperCase) {
    return 'Password harus mengandung setidaknya satu huruf besar.';
  }
  if (!hasLowerCase) {
    return 'Password harus mengandung setidaknya satu huruf kecil.';
  }
  if (!hasNumber) {
    return 'Password harus mengandung setidaknya satu angka.';
  }

  return 'Password kuat!';
}

// Contoh penggunaan:
console.log(checkPasswordStrength('password123'));  // Terlalu pendek, tidak ada huruf besar
console.log(checkPasswordStrength('Password123')); // Password kuat!
console.log(checkPasswordStrength('Pass1'));       // Terlalu pendek
```
Fungsi ini akan memberikan pesan spesifik jika password tidak memenuhi kriteria. Anda bisa menambahkan validasi karakter khusus juga!

