แน่นอนครับ นี่คือฟังก์ชัน JavaScript ที่คำนวณอายุจากวันเกิด:

```javascript
function calculateAge(birthDate) {
  const today = new Date();
  const dob = new Date(birthDate);

  let age = today.getFullYear() - dob.getFullYear();
  const monthDiff = today.getMonth() - dob.getMonth();

  if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < dob.getDate())) {
    age--;
  }
  return age;
}

// ตัวอย่างการใช้งาน
console.log(`คุณอายุ: ${calculateAge('1990-05-15')} ปี`); // สมมติวันนี้ 2024-07-20 จะได้ 34
console.log(`คุณอายุ: ${calculateAge('2000-07-25')} ปี`); // สมมติวันนี้ 2024-07-20 จะได้ 23
```
แค่ส่งสตริงวันเกิดในรูปแบบที่ Date constructor เข้าใจได้ ฟังก์ชันนี้ก็จะคำนวณอายุให้เลยครับ

ได้เลยครับ PHP มีฟังก์ชันในตัวที่ทำได้ง่ายๆ แบบนี้ครับ:

```php
<?php

function removeDuplicates(array $arr): array {
    return array_unique($arr);
}

// ตัวอย่างการใช้งาน
$numbers = [1, 2, 2, 3, 4, 4, 5, 1];
$uniqueNumbers = removeDuplicates($numbers);
echo "Original array: " . implode(', ', $numbers) . "\n";
echo "Unique array: " . implode(', ', $uniqueNumbers) . "\n";

$colors = ['red', 'green', 'blue', 'red', 'yellow'];
$uniqueColors = removeDuplicates($colors);
echo "Original array: " . implode(', ', $colors) . "\n";
echo "Unique array: " . implode(', ', $uniqueColors) . "\n";

?>
```
ฟังก์ชัน `array_unique()` จะจัดการให้คุณเองเลยครับ สะดวกมากๆ

แน่นอนครับ นี่คือฟังก์ชัน C# สำหรับตรวจสอบว่าสตริงประกอบด้วยเฉพาะตัวอักษรและตัวเลขเท่านั้น:

```csharp
using System.Linq;

public static class StringValidator
{
    public static bool IsAlphaNumeric(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            return false;
        }
        // ตรวจสอบว่าทุกตัวอักษรในสตริงเป็นตัวอักษรหรือตัวเลข
        return text.All(char.IsLetterOrDigit);
    }

    public static void Main(string[] args)
    {
        Console.WriteLine($"\"HelloWorld123\" is alphanumeric: {IsAlphaNumeric("HelloWorld123")}"); // True
        Console.WriteLine($"\"Hello World\" is alphanumeric: {IsAlphaNumeric("Hello World")}");   // False
        Console.WriteLine($"\"test@example\" is alphanumeric: {IsAlphaNumeric("test@example")}"); // False
        Console.WriteLine($"\"\" is alphanumeric: {IsAlphaNumeric("")}");                       // False
    }
}
```
เมธอด `char.IsLetterOrDigit` จะช่วยให้คุณตรวจสอบได้อย่างง่ายดายครับ

ได้เลยครับ นี่คือฟังก์ชัน JavaScript ที่ใช้ `URL` constructor ในตัวเพื่อตรวจสอบความถูกต้องของ URL:

```javascript
function isValidUrl(urlString) {
  try {
    new URL(urlString);
    return true;
  } catch (e) {
    return false;
  }
}

// ตัวอย่างการใช้งาน
console.log(`'https://www.rnai.io' is valid: ${isValidUrl('https://www.rnai.io')}`); // True
console.log(`'http://localhost:3000/path' is valid: ${isValidUrl('http://localhost:3000/path')}`); // True
console.log(`'invalid-url' is valid: ${isValidUrl('invalid-url')}`); // False
console.log(`'ftp://example.com' is valid: ${isValidUrl('ftp://example.com')}`); // True
```
การใช้ `new URL()` เป็นวิธีที่เชื่อถือได้และครอบคลุมตามมาตรฐานครับ

แน่นอนครับ นี่คือฟังก์ชัน Go ที่จัดรูปแบบตัวเลขให้เป็นสกุลเงิน (เช่น บาทไทย) โดยใช้ `strconv` และ `fmt`:

```go
package main

import (
	"fmt"
	"strconv"
)

// FormatCurrency จัดรูปแบบตัวเลขให้เป็นสกุลเงิน (เช่น "฿ 1,234.56")
func FormatCurrency(amount float64) string {
	// แปลงเป็นสตริงทศนิยม 2 ตำแหน่ง
	s := strconv.FormatFloat(amount, 'f', 2, 64)

	// แยกส่วนจำนวนเต็มและทศนิยม
	parts := strings.Split(s, ".")
	integerPart := parts[0]
	decimalPart := parts[1]

	// เพิ่มคอมม่าในส่วนจำนวนเต็ม
	formattedInteger := ""
	for i, r := range integerPart {
		formattedInteger += string(r)
		if (len(integerPart)-i-1)%3 == 0 && i != len(integerPart)-1 && r != '-'
		{
			formattedInteger += ","
		}
	}

	return fmt.Sprintf("฿ %s.%s", formattedInteger, decimalPart)
}

func main() {
	fmt.Println(FormatCurrency(1234.56))   // ฿ 1,234.56
	fmt.Println(FormatCurrency(98765.4321)) // ฿ 98,765.43
	fmt.Println(FormatCurrency(100.00))    // ฿ 100.00
	fmt.Println(FormatCurrency(7.8))       // ฿ 7.80
}
```
ฟังก์ชันนี้จะใส่เครื่องหมายคอมม่าและแสดงผลเป็นทศนิยมสองตำแหน่งให้เลยครับ

การตรวจสอบความแข็งแรงของรหัสผ่านที่ซับซ้อนมากๆ อาจต้องพิจารณาปัจจัยหลายอย่างและอาจเป็นเรื่องที่ละเอียดอ่อนด้านความปลอดภัยครับ Rnai แนะนำให้ใช้ไลบรารีที่ได้รับการยอมรับ หรือพึ่งพาการตรวจสอบจากฝั่งเซิร์ฟเวอร์จะปลอดภัยกว่าครับ

แต่ถ้าต้องการฟังก์ชันพื้นฐานสำหรับตรวจสอบความยาวและประเภทตัวอักษรเบื้องต้น นี่คือตัวอย่างครับ:

```javascript
function checkPasswordStrength(password) {
  const minLength = 8;
  const hasUppercase = /[A-Z]/.test(password);
  const hasLowercase = /[a-z]/.test(password);
  const hasNumber = /\d/.test(password);
  const hasSpecialChar = /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password);

  let strength = 0;
  if (password.length >= minLength) strength++;
  if (hasUppercase) strength++;
  if (hasLowercase) strength++;
  if (hasNumber) strength++;
  if (hasSpecialChar) strength++;

  return {
    score: strength, // 0-5
    isStrong: strength >= 4 && password.length >= minLength,
    feedback: {
      minLength: password.length >= minLength,
      uppercase: hasUppercase,
      lowercase: hasLowercase,
      number: hasNumber,
      specialChar: hasSpecialChar
    }
  };
}

// ตัวอย่างการใช้งาน
console.log(checkPasswordStrength('Password123!')); // strong
console.log(checkPasswordStrength('short'));       // weak
```
ฟังก์ชันนี้จะให้คะแนนและความเห็นพื้นฐานครับ ถ้าต้องการความแข็งแกร่งขั้นสูง ควรใช้ `zxcvbn` หรือส่งไปตรวจสอบที่เซิร์ฟเวอร์จะปลอดภัยกว่าครับ

Saya mengerti. Kesalahannya ada pada kondisi loop Anda, yaitu `i <= arr.length`. Ini akan mencoba mengakses indeks di luar batas array. Perbaikannya seperti ini:

```javascript
function calculateAverage(arr) {
  let sum = 0;
  for (let i = 0; i < arr.length; i++) { // Ubah <= menjadi <
    sum += arr[i];
  }
  return sum / arr.length;
}

// Contoh penggunaan:
console.log(calculateAverage([10, 20, 30])); // Output: 20
```
Array di JavaScript dimulai dari indeks 0 hingga `length - 1`, jadi `i < arr.length` sudah benar. Semoga membantu!

Betul sekali, kode Anda rentan SQL Injection karena langsung menyatukan input pengguna ke dalam query. Solusi terbaik adalah menggunakan *prepared statements*. Ini contoh perbaikannya:

```php
<?php
// Asumsi $conn adalah koneksi mysqli Anda

$username = $_POST['username'];
$password = $_POST['password'];

// Gunakan prepared statements untuk keamanan
$stmt = $conn->prepare("SELECT * FROM users WHERE username = ? AND password = ?");
$stmt->bind_param("ss", $username, $password); // 'ss' berarti dua string
$stmt->execute();
$result = $stmt->get_result();

// ... lanjutkan dengan memproses $result
$stmt->close();
?>
```
Dengan cara ini, input pengguna tidak akan diinterpretasikan sebagai bagian dari perintah SQL, sehingga jauh lebih aman. Ada lagi yang ingin Anda amankan?

Ah, saya tahu! Anda melupakan statement `return` di akhir fungsi Anda. Meskipun `fullName` sudah dihitung, nilainya tidak dikembalikan. Berikut perbaikannya:

```typescript
function formatName(firstName: string, lastName: string): string {
  const fullName = `${firstName} ${lastName}`;
  return fullName; // Tambahkan 'return' di sini
}

// Contoh penggunaan:
