ນີ້ແມ່ນ Tab component ພ້ອມໃຊ້ງານ:

```tsx
import React, { useState, ReactNode } from 'react';

interface TabItem {
  label: string;
  content: ReactNode;
}

interface TabsProps {
  tabs: TabItem[];
  initialActiveTab?: number;
}

export function Tabs({ tabs, initialActiveTab = 0 }: TabsProps) {
  const [activeIndex, setActiveIndex] = useState(initialActiveTab);

  return (
    <div>
      <div style={{ borderBottom: '1px solid #ccc' }}>
        {tabs.map((tab, index) => (
          <button
            key={index}
            onClick={() => setActiveIndex(index)}
            style={{
              padding: '10px 15px',
              cursor: 'pointer',
              border: 'none',
              background: 'transparent',
              borderBottom: activeIndex === index ? '2px solid blue' : 'none',
              fontWeight: activeIndex === index ? 'bold' : 'normal',
            }}
          >
            {tab.label}
          </button>
        ))}
      </div>
      <div style={{ padding: '15px' }}>
        {tabs[activeIndex] ? tabs[activeIndex].content : null}
      </div>
    </div>
  );
}
```
ມັນໃຊ້ `useState` ເພື່ອຈັດການແຖບທີ່ເປີດໃຊ້ງານຢູ່. ຕ້ອງການໃຫ້ເພີ່ມ router integration ບໍ່?

