```tsx
import React from 'react';

interface ProgressBarProps {
  progress: number; // 0-100
}

export function ProgressBar({ progress }: ProgressBarProps) {
  const clampedProgress = Math.max(0, Math.min(100, progress));

  return (
    <div style={{ width: '100%', background: '#e0e0e0', borderRadius: '4px', height: '20px', overflow: 'hidden' }}>
      <div
        style={{
          width: `${clampedProgress}%`,
          background: '#4CAF50',
          height: '100%',
          borderRadius: '4px',
          transition: 'width 0.5s ease-in-out',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: 'white',
          fontSize: '12px'
        }}
      >
        {clampedProgress > 5 && `${clampedProgress}%`}
      </div>
    </div>
  );
}
```
ມັນຈະປັບຄວາມກວ້າງຕາມຄ່າ `progress`. ຕ້ອງການໃຫ້ປັບສີຕາມເປີເຊັນທີ່ແຕກຕ່າງກັນບໍ່?

ນີ້ແມ່ນ Tooltip component ທີ່ສະແດງຂໍ້ຄວາມເມື່ອ hover:

```tsx
import React, { useState, ReactNode } from 'react';

interface TooltipProps {
  text: string;
  children: ReactNode;
}

export function Tooltip({ text, children }: TooltipProps) {
  const [isVisible, setIsVisible] = useState(false);

  return (
    <div style={{ position: 'relative', display: 'inline-block' }}
      onMouseEnter={() => setIsVisible(true)}
      onMouseLeave={() => setIsVisible(false)}>
      {children}
      {isVisible && (
        <div style={{
          position: 'absolute',
          bottom: '120%', // Position above the children
          left: '50%',
          transform: 'translateX(-50%)',
          background: '#333',
          color: 'white',
          padding: '8px',
          borderRadius: '4px',
          whiteSpace: 'nowrap',
          zIndex: 10
        }}>
          {text}
        </div>
      )}
    </div>
  );
}
```
ທ່ານສາມາດໃຊ້ `text` prop ເພື່ອໃສ່ຂໍ້ຄວາມ. ຕ້ອງການໃຫ້ເພີ່ມຕົວເລືອກຕໍາແໜ່ງ (ເທິງ, ລຸ່ມ, ຊ້າຍ, ຂວາ) ບໍ່?

