```tsx
import React, { useState, SelectHTMLAttributes } from 'react';

interface DropdownOption {
  value: string;
  label: string;
}

interface DropdownProps extends SelectHTMLAttributes<HTMLSelectElement> {
  options: DropdownOption[];
  label?: string;
}

export const Dropdown: React.FC<DropdownProps> = ({ options, label, id, ...rest }) => {
  const selectId = id || React.useId();
  const [selectedValue, setSelectedValue] = useState(rest.defaultValue as string || options[0]?.value || '');

  const handleChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedValue(event.target.value);
    if (rest.onChange) {
      rest.onChange(event);
    }
  };

  return (
    <div style={{ marginBottom: '1rem' }}>
      {label && <label htmlFor={selectId} style={{ display: 'block', marginBottom: '0.4rem', fontWeight: 'bold' }}>{label}</label>}
      <select
        id={selectId}
        value={selectedValue}
        onChange={handleChange}
        style={{
          padding: '0.6rem',
          borderRadius: '4px',
          border: '1px solid #ccc',
          width: '100%',
          backgroundColor: 'white',
          boxSizing: 'border-box'
        }}
        {...rest}
      >
        {options.map(option => (
          <option key={option.value} value={option.value}>
            {option.label}
          </option>
        ))}
      </select>
    </div>
  );
};
```
