ນີ້ແມ່ນ `ToggleSwitch` component ງ່າຍໆ:

```tsx
import { InputHTMLAttributes } from "react";

type Props = Omit<InputHTMLAttributes<HTMLInputElement>, 'type'> & {
  checked: boolean;
  onChange: (checked: boolean) => void;
  label?: string;
};

export function ToggleSwitch({ checked, onChange, label, id, ...rest }: Props) {
  const toggleId = id || `toggle-${Math.random().toString(36).substr(2, 9)}`;

  return (
    <div className="flex items-center space-x-2">
      <input
        type="checkbox"
        id={toggleId}
        checked={checked}
        onChange={(e) => onChange(e.target.checked)}
        className="sr-only peer"
        {...rest}
      />
      <label
        htmlFor={toggleId}
        className="relative block w-11 h-6 bg-gray-200 rounded-full peer-checked:bg-blue-600 cursor-pointer transition-colors duration-200"
      >
        <span className="absolute left-1 top-1 w-4 h-4 bg-white rounded-full transition-transform duration-200 peer-checked:translate-x-full"></span>
      </label>
      {label && <label htmlFor={toggleId} className="text-gray-700 cursor-pointer">{label}</label>}
    </div>
  );
}
```
(ໃຊ້ Tailwind CSS) ມັນໃຊ້ `sr-only` ເພື່ອເຊື່ອງ input ຕົວຈິງ, ແຕ່ຍັງສາມາດໃຊ້ງານໄດ້.

