ນີ້ແມ່ນ `Avatar` component ທີ່ສະແດງຮູບພາບ ຫຼື ຕົວອັກສອນເລີ່ມຕົ້ນ:

```tsx
import { useState } from "react";

type Props = {
  src?: string;
  alt: string;
  size?: number; // in pixels
  fallbackChar?: string; // first letter of alt by default
};

export function Avatar({ src, alt, size = 40, fallbackChar }: Props) {
  const [imageError, setImageError] = useState(false);
  const char = fallbackChar || alt.charAt(0).toUpperCase();

  return (
    <div
      className="flex items-center justify-center rounded-full bg-gray-200 text-gray-600 font-semibold overflow-hidden flex-shrink-0"
      style={{ width: size, height: size, fontSize: size / 2.5 }}
    >
      {src && !imageError ? (
        <img
          src={src}
          alt={alt}
          className="w-full h-full object-cover"
          onError={() => setImageError(true)}
        />
      ) : (
        <span>{char}</span>
      )}
    </div>
  );
}
```
ມັນຈະສະແດງຕົວອັກສອນທຳອິດຖ້າຮູບພາບໂຫຼດບໍ່ໄດ້ ຫຼື ບໍ່ມີ `src` ເດີ.

