ဟုတ်ကဲ့၊ factorial တွက်ဖို့ ဒီ JavaScript လုပ်ဆောင်ချက်လေးက အဆင်ပြေပါလိမ့်မယ်။

```javascript
function calculateFactorial(n) {
  if (n < 0) {
    return "Input must be a non-negative number";
  }
  if (n === 0 || n === 1) {
    return 1;
  }
  let result = 1;
  for (let i = 2; i <= n; i++) {
    result *= i;
  }
  return result;
}

// Usage example
console.log(calculateFactorial(5)); // 120
console.log(calculateFactorial(0)); // 1
console.log(calculateFactorial(7)); // 5040
```
သူက negative ဂဏန်းတွေကိုလည်း စစ်ဆေးပေးပါတယ်။

ရပါတယ်ခင်ဗျာ။ ဒီ JavaScript လုပ်ဆောင်ချက်လေးက ဆဲလ်စီးယပ်စ်ကို ဖာရင်ဟိုက်ပြောင်းပေးပါလိမ့်မယ်။

```javascript
function celsiusToFahrenheit(celsius) {
  if (typeof celsius !== 'number') {
    return "Input must be a number";
  }
  return (celsius * 9/5) + 32;
}

// Usage example
console.log(celsiusToFahrenheit(0));   // 32
console.log(celsiusToFahrenheit(25));  // 77
console.log(celsiusToFahrenheit(100)); // 212
```
ရလဒ်ကို လိုအပ်သလို ဒသမနေရာ ချိန်ညှိနိုင်ပါတယ်။

ဟုတ်ကဲ့၊ array ထဲက ဂဏန်းအားလုံးကို ပေါင်းပေးဖို့ ဒီ JavaScript လုပ်ဆောင်ချက်လေးက အဆင်ပြေပါလိမ့်မယ်။

```javascript
function sumArray(numbers) {
  if (!Array.isArray(numbers)) {
    return "Input must be an array";
  }
  let total = 0;
  for (const num of numbers) {
    if (typeof num === 'number') {
      total += num;
    }
  }
  return total;
}

// Usage example
console.log(sumArray([1, 2, 3, 4, 5])); // 15
console.log(sumArray([]));              // 0
console.log(sumArray([10, -5, 20]));    // 25
```
ဂဏန်းမဟုတ်တဲ့အရာတွေကိုလည်း ကျော်သွားအောင် ရေးထားပါတယ်။

