Chào bạn, đây là cách bạn có thể tạo endpoint DELETE trong Express để xóa sản phẩm theo ID:

```javascript
const express = require('express');
const app = express();
const port = 3000;

let products = [
  { id: 1, name: 'Sản phẩm A' },
  { id: 2, name: 'Sản phẩm B' },
  { id: 3, name: 'Sản phẩm C' },
];

app.delete('/products/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const initialLength = products.length;
  products = products.filter(p => p.id !== id);

  if (products.length < initialLength) {
    res.status(200).json({ message: `Sản phẩm với ID ${id} đã được xóa.` });
  } else {
    res.status(404).json({ message: `Không tìm thấy sản phẩm với ID ${id}.` });
  }
});

app.listen(port, () => {
  console.log(`Server đang chạy tại http://localhost:${port}`);
});
```
Endpoint này sẽ trả về 200 nếu xóa thành công và 404 nếu không tìm thấy. Bạn có muốn thêm bảo mật cho endpoint này không?

