เยี่ยมเลยครับ นี่คือ FastAPI endpoint สำหรับอัปเดตข้อมูลหนังสือตาม ID:

```python
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import Optional

app = FastAPI()

class Book(BaseModel):
    title: str
    author: str
    year: Optional[int] = None

books_db = {
    "1": {"title": "The Great Gatsby", "author": "F. Scott Fitzgerald", "year": 1925},
    "2": {"title": "1984", "author": "George Orwell", "year": 1949}
} # สมมติฐานข้อมูลชั่วคราว

@app.put("/books/{book_id}")
async def update_book(book_id: str, book: Book):
    if book_id not in books_db:
        raise HTTPException(status_code=404, detail="Book not found")
    books_db[book_id].update(book.dict())
    return {"message": "Book updated successfully", "book": books_db[book_id]}
```
