ဒါက `category` နဲ့ `minPrice` query parameters ကို အသုံးပြုပြီး product တွေကို စစ်ထုတ်မယ့် Express GET endpoint ပါ။

```javascript
const express = require('express');
const app = express();
const port = 3000;

const products = [
  { id: 1, name: 'Shirt', category: 'Apparel', price: 25 },
  { id: 2, name: 'Pants', category: 'Apparel', price: 50 },
  { id: 3, name: 'Keyboard', category: 'Electronics', price: 75 },
  { id: 4, name: 'Mouse', category: 'Electronics', price: 30 }
];

app.get('/products/search', (req, res) => {
  const { category, minPrice } = req.query;
  let filteredProducts = products;

  if (category) {
    filteredProducts = filteredProducts.filter(p => p.category.toLowerCase() === category.toLowerCase());
  }
  if (minPrice) {
    filteredProducts = filteredProducts.filter(p => p.price >= parseFloat(minPrice));
  }
  res.send(filteredProducts);
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});
```
`http://localhost:3000/products/search?category=electronics&minPrice=30` ကို စမ်းကြည့်နိုင်ပါတယ်။

