ได้เลยครับ นี่คือคอมโพเนนต์ `Tabs` และ `TabPanel` ที่ช่วยให้คุณสร้างแถบเมนูได้:

```tsx
import React, { useState, ReactNode } from 'react';

type TabsProps = {
  children: ReactNode;
  defaultActiveKey?: string;
};

type TabPanelProps = {
  tabKey: string;
  tabTitle: string;
  children: ReactNode;
};

export function TabPanel({ children }: TabPanelProps) {
  return <div>{children}</div>;
}

export function Tabs({ children, defaultActiveKey }: TabsProps) {
  const panels = React.Children.toArray(children).filter(
    (child): child is React.ReactElement<TabPanelProps> =>
      React.isValidElement(child) && (child.type as any).name === 'TabPanel'
  );
  const [activeKey, setActiveKey] = useState(defaultActiveKey || panels[0]?.props.tabKey);

  return (
    <div>
      <div style={{ display: 'flex', borderBottom: '1px solid #eee', marginBottom: '16px' }}>
        {panels.map((panel) => (
          <button
            key={panel.props.tabKey}
            onClick={() => setActiveKey(panel.props.tabKey)}
            style={{
              padding: '10px 15px', border: 'none', backgroundColor: 'transparent',
              cursor: 'pointer', fontSize: '16px',
              borderBottom: activeKey === panel.props.tabKey ? '2px solid #007bff' : 'none',
              color: activeKey === panel.props.tabKey ? '#007bff' : '#555',
              fontWeight: activeKey === panel.props.tabKey ? 'bold' : 'normal',
            }}
          >
            {panel.props.tabTitle}
          </button>
        ))}
      </div>
      <div>
        {panels.find(panel => panel.props.tabKey === activeKey)}
      </div>
    </div>
  );
}
```
ใช้งานแบบนี้ครับ:
```tsx
<Tabs defaultActiveKey="tab1">
  <TabPanel tabKey="tab1" tabTitle="แท็บแรก">เนื้อหาสำหรับแท็บแรก</TabPanel>
  <TabPanel tabKey="tab2" tabTitle="แท็บสอง">เนื้อหาสำหรับแท็บสอง</TabPanel>
</Tabs>
```
