Narito ang isang halimbawa ng `useForm` custom hook at isang simpleng `Form` component para sa state management:

```tsx
import { useState, ChangeEvent, FormEvent } from "react";

// Custom Hook
interface FormState {
  [key: string]: string;
}

interface UseFormReturn {
  formData: FormState;
  handleChange: (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  resetForm: () => void;
}

export function useForm(initialState: FormState): UseFormReturn {
  const [formData, setFormData] = useState<FormState>(initialState);

  const handleChange = (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const resetForm = () => setFormData(initialState);

  return { formData, handleChange, resetForm };
}

// Form Component (example usage)
interface MyFormComponentProps {
  onSubmit: (data: FormState) => void;
}

export function MyForm({ onSubmit }: MyFormComponentProps) {
  const { formData, handleChange, resetForm } = useForm({ username: "", email: "" });

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
    resetForm();
  };

  return (
    <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '10px', maxWidth: '300px' }}>
      <input
        type="text"
        name="username"
        value={formData.username}
        onChange={handleChange}
        placeholder="Username"
        style={{ padding: '8px', borderRadius: '4px', border: '1px solid #ccc' }}
      />
      <input
        type="email"
        name="email"
        value={formData.email}
        onChange={handleChange}
        placeholder="Email"
        style={{ padding: '8px', borderRadius: '4px', border: '1px solid #ccc' }}
      />
      <button type="submit" style={{ padding: '10px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>
        Submit
      </button>
    </form>
  );
}
```
Ang `useForm` hook ay madaling gamitin para sa anumang form. Gusto mo bang magdagdag ng validation sa hook?

