```tsx
import React from 'react';

type SpinnerProps = {
  size?: number; // Size in pixels (width and height)
  color?: string; // Color of the spinner
  thickness?: number; // Thickness of the spinner border
  speed?: string; // Animation speed, e.g., '1s'
};

export function Spinner({ size = 24, color = '#3498db', thickness = 4, speed = '0.8s' }: SpinnerProps) {
  const spinnerStyle: React.CSSProperties = {
    width: size,
    height: size,
    border: `${thickness}px solid #f3f3f3`, // Light grey border
    borderTop: `${thickness}px solid ${color}`, // Colored top border
    borderRadius: '50%',
    animation: `spin ${speed} linear infinite`,
  };

  const keyframesStyle = `
    @keyframes spin {
      0% { transform: rotate(0deg); }
      100% { transform: rotate(360deg); }
    }
  `;

  return (
    <>
      <style>{keyframesStyle}</style>
      <div style={spinnerStyle} role="status">
        <span className="sr-only">Loading...</span>
      </div>
    </>
  );
}
```
