អាចប្រើបាន: `<Input label="ឈ្មោះ" error="ឈ្មោះមិនអាចទទេបានទេ" />`។ ចង់ឱ្យវាមាន Placeholder ទេ?

បានភ្លាម! នេះជា component Select ដែលអាចទទួល array នៃ options:

```tsx
import React, { SelectHTMLAttributes } from 'react';

type Option = { value: string; label: string; };

type SelectProps = SelectHTMLAttributes<HTMLSelectElement> & {
  options: Option[];
  label?: string;
};

export function Select({ options, label, id, ...rest }: SelectProps) {
  const selectId = id || (label ? label.toLowerCase().replace(/\s/g, '-') : 'select-box');
  return (
    <div>
      {label && <label htmlFor={selectId}>{label}</label>}
      <select id={selectId} {...rest}>
        {options.map(option => (
          <option key={option.value} value={option.value}>
            {option.label}
          </option>
        ))}
      </select>
    </div>
  );
}
```
ឧទាហរណ៍: `<Select options={[{value: 'apple', label: 'ផ្លែប៉ោម'}]} label="ជ្រើសរើសផ្លែឈើ" />`។

នេះជា Modal component មួយដែលអាចបង្ហាញមាតិកា និងមានប៊ូតុងបិទ:

