Here's an Express example for updating a product by ID, typically using a `PUT` or `PATCH` request:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json());

// Dummy product data
let products = [{ id: '1', name: 'Keyboard', price: 75 }];

app.put('/products/:id', (req, res) => {
  const productId = req.params.id;
  const updatedProductData = req.body;

  const productIndex = products.findIndex(p => p.id === productId);

  if (productIndex !== -1) {
    products[productIndex] = { ...products[productIndex], ...updatedProductData };
    res.json({ message: 'Product updated successfully', product: products[productIndex] });
  } else {
    res.status(404).json({ message: 'Product not found' });
  }
});

app.listen(port, () => {
  console.log(`Express app listening at http://localhost:${port}`);
});
```

This `PUT` endpoint will replace or merge existing product data. Would you like to implement a `GET` endpoint to retrieve all products?

You got it! Here's a JavaScript function to check for palindromes, ignoring case and non-alphanumeric characters:

```javascript
function isPalindrome(str) {
  const cleanedStr = str.toLowerCase().replace(/[^a-z0-9]/g, '');
  const reversedStr = cleanedStr.split('').reverse().join('');
  return cleanedStr === reversedStr;
}

// Example usage:
console.log(isPalindrome('madam'));           // true
console.log(isPalindrome('A man, a plan, a canal: Panama')); // true
console.log(isPalindrome('hello'));           // false
```
