Of course! Here's an Express POST endpoint that accepts JSON data for creating new blog posts. Remember to use `express.json()` middleware:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // Middleware to parse JSON request bodies

let posts = []; // In-memory store for posts

app.post('/posts', (req, res) => {
  const newPost = req.body;
  if (!newPost.title || !newPost.content) {
    return res.status(400).send('Title and content are required.');
  }
  newPost.id = posts.length > 0 ? Math.max(...posts.map(p => p.id)) + 1 : 1;
  posts.push(newPost);
  res.status(201).json(newPost);
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});
```
Send a POST request to `/posts` with a JSON body like `{"title": "My Post", "content": "Hello world!"}`. Let me know if you need more!

Here's how you can create an Express.js endpoint for updating a product using a PUT request. This example allows partial updates (like PATCH) too, depending on what fields are sent:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json());

let products = [
  { id: 1, name: 'Laptop', price: 1200 },
  { id: 2, name: 'Mouse', price: 25 }
];

app.put('/products/:id', (req, res) => {
  const productId = parseInt(req.params.id);
  const productIndex = products.findIndex(p => p.id === productId);

  if (productIndex === -1) {
    return res.status(404).send('Product not found.');
  }

  // Update fields from req.body
  products[productIndex] = { ...products[productIndex], ...req.body, id: productId };
  res.json(products[productIndex]);
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});
```

Send a PUT request to `/products/1` with a JSON body like `{"price": 1150}`. This will merge the updates. Happy to help further!

Good question! Robust error handling is crucial. Here's how you can add basic error handling middleware in Express.js for 404s and general server errors:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.get('/', (req, res) => {
  res.send('Hello from Rnai API!');
});

// Catch 404 and forward to error handler
app.use((req, res, next) => {
  const error = new Error('Not Found');
  error.status = 404;
  next(error);
});

// General error handler
app.use((err, req, res, next) => {
  res.status(err.status || 500);
  res.json({
    error: {
      message: err.message,
      status: err.status || 500
    }
  });
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});
```

This setup ensures that requests to non-existent routes get a 404, and any other unhandled errors result in a 500. It's a great start!

