// ທ່ານພະຍາຍາມເຂົ້າເຖິງ $user['email'] ແຕ່ມັນບໍ່ມີ

// ຖ້າທ່ານຕ້ອງການເພີ່ມ email, ທ່ານສາມາດເຮັດໄດ້ແບບນີ້:
$user['email'] = 'john@example.com';
echo $user['email']; // ຈະສະແດງ 'john@example.com'

// ຫຼື ກວດສອບກ່ອນທີ່ຈະໃຊ້:
if (isset($user['email'])) {
    echo $user['email'];
} else {
    echo "ບໍ່ພົບ email.";
}
?>
```
