ពិតណាស់! នេះជា function JavaScript ងាយស្រួលសម្រាប់គណនាអាយុពីថ្ងៃខែឆ្នាំកំណើត:

```javascript
function calculateAge(birthdateString) {
  const birthdate = new Date(birthdateString);
  const today = new Date();

  let age = today.getFullYear() - birthdate.getFullYear();
  const monthDifference = today.getMonth() - birthdate.getMonth();

  if (monthDifference < 0 || (monthDifference === 0 && today.getDate() < birthdate.getDate())) {
    age--;
  }
  return age;
}

// ឧទាហរណ៍នៃការប្រើប្រាស់:
console.log(calculateAge('1990-05-15')); // ឧទាហរណ៍នឹងបង្ហាញអាយុបច្ចុប្បន្ន
console.log(calculateAge('2005-12-01')); // ឧទាហរណ៍នឹងបង្ហាញអាយុបច្ចុប្បន្ន
```
