បានเลย! នេះជា function PHP សម្រាប់រៀបចំលេខទូរស័ព្ទឲ្យមានទម្រង់ស្អាត:

```php
<?php

function formatPhoneNumber(string $phoneNumber): string
{
    // ដកតួអក្សរដែលមិនមែនជាលេខចេញ
    $cleaned = preg_replace('/[^0-9]/', '', $phoneNumber);

    // ឧទាហរណ៍៖ +855 12 345 678
    if (preg_match('/^(855)(\d{2})(\d{3})(\d{3})$/', $cleaned, $matches)) {
        return '+' . $matches[1] . ' ' . $matches[2] . ' ' . $matches[3] . ' ' . $matches[4];
    }

    // ឧទាហរណ៍៖ 012 345 678
    if (preg_match('/^(0)(\d{2})(\d{3})(\d{3})$/', $cleaned, $matches)) {
        return $matches[1] . $matches[2] . ' ' . $matches[3] . ' ' . $matches[4];
    }

