        console.log("Invalid item price.");
        return false;
    }
    console.log(`Processing order for ${quantity} x ${item.name} at ${item.price * quantity}`);
    return true;
}
console.log(processOrderClean({name: 'Coffee', price: 5}, 2));
console.log(processOrderClean({name: 'Tea'}, 1));
```
