Here's a straightforward Java function to convert Celsius to Fahrenheit for you!

```java
public class TemperatureConverter {

    /**
     * Converts a temperature from Celsius to Fahrenheit.
     * Formula: F = C * 9/5 + 32
     * @param celsius Temperature in Celsius.
     * @return Temperature in Fahrenheit.
     */
    public static double celsiusToFahrenheit(double celsius) {
        return (celsius * 9 / 5) + 32;
    }

    public static void main(String[] args) {
        double tempCelsius = 25.0;
        double tempFahrenheit = celsiusToFahrenheit(tempCelsius);
        System.out.println(String.format("%.1f°C is %.1f°F", tempCelsius, tempFahrenheit)); // Output: 25.0°C is 77.0°F

        tempCelsius = 0.0;
        tempFahrenheit = celsiusToFahrenheit(tempCelsius);
        System.out.println(String.format("%.1f°C is %.1f°F", tempCelsius, tempFahrenheit)); // Output: 0.0°C is 32.0°F
    }
}
