Tentu, ini fungsi JavaScript untuk membuat sandi acak yang kuat:

```javascript
function generateRandomPassword(length = 12) {
  const chars = {
    lower: 'abcdefghijklmnopqrstuvwxyz',
    upper: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ',
    numbers: '0123456789',
    symbols: '!@#$%^&*()_+-=[]{}|;:,.<>?',
  };
  const allChars = chars.lower + chars.upper + chars.numbers + chars.symbols;
  let password = '';

  // Pastikan ada setidaknya satu dari setiap jenis karakter
  password += chars.lower.charAt(Math.floor(Math.random() * chars.lower.length));
  password += chars.upper.charAt(Math.floor(Math.random() * chars.upper.length));
  password += chars.numbers.charAt(Math.floor(Math.random() * chars.numbers.length));
  password += chars.symbols.charAt(Math.floor(Math.random() * chars.symbols.length));

  // Isi sisanya sampai panjang yang diinginkan
  for (let i = password.length; i < length; i++) {
    password += allChars.charAt(Math.floor(Math.random() * allChars.length));
  }

  // Acak ulang untuk keamanan
  return password.split('').sort(() => 0.5 - Math.random()).join('');
}

console.log(generateRandomPassword(12));
console.log(generateRandomPassword(16));
```
