Tentu, ini fungsi C# untuk memeriksa palindrom dengan mengabaikan huruf besar/kecil dan spasi:

```csharp
using System;
using System.Linq;

public class PalindromeChecker
{
    public static bool IsPalindrome(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            return true; // String kosong atau null bisa dianggap palindrom
        }

        // Bersihkan teks: ubah ke huruf kecil dan hapus karakter non-alfanumerik
        string cleanedText = new string(text.Where(char.IsLetterOrDigit).ToArray()).ToLower();

        // Balikkan teks
        char[] charArray = cleanedText.ToCharArray();
        Array.Reverse(charArray);
        string reversedText = new string(charArray);

        return cleanedText.Equals(reversedText);
    }

    public static void Main(string[] args)
    {
        Console.WriteLine($"'Madam': {IsPalindrome("Madam")}");           // True
        Console.WriteLine($"'A man a plan a canal Panama': {IsPalindrome("A man a plan a canal Panama")}"); // True
        Console.WriteLine($"'Hello': {IsPalindrome("Hello")}");           // False
        Console.WriteLine($"'Racecar': {IsPalindrome("Racecar")}");         // True
    }
}
```
Fungsi ini fleksibel dan akan bekerja dengan baik! Ada pertanyaan lain?

