package main

import (
	"fmt"
	"net/url"
)

// IsValidURL memeriksa apakah sebuah string adalah URL yang valid.
func IsValidURL(s string) bool {
	u, err := url.ParseRequestURI(s)
	return err == nil && u.IsAbs()
}

func main() {
	fmt.Printf("'%s' valid? %t\n", "https://rnai.io", IsValidURL("https://rnai.io")) // true
	fmt.Printf("'%s' valid? %t\n", "not-a-url", IsValidURL("not-a-url"))           // false
	fmt.Printf("'%s' valid? %t\n", "/relative/path", IsValidURL("/relative/path")) // false (not absolute)
}
```
Penting untuk memeriksa `IsAbs()` juga untuk URL absolut. Ada pertanyaan lain?

