```python
def count_words_in_file(file_path: str) -> int:
    try:
        with open(file_path, 'r', encoding='utf-8') as file:
            content = file.read()
            words = content.split()  # ແຍກຂໍ້ຄວາມຕາມຊ່ອງວ່າງ
            return len(words)
    except FileNotFoundError:
