        return 0
    except Exception as e:
        print(f"ເກີດຂໍ້ຜິດພາດ: {e}")
        return 0

if __name__ == "__main__":
    # ຕົວຢ່າງ: ສ້າງໄຟລ໌ຂໍ້ຄວາມເພື່ອທົດສອບ
    with open("sample.txt", "w", encoding="utf-8") as f:
        f.write("ສະບາຍດີ, ນີ້ແມ່ນຂໍ້ຄວາມຕົວຢ່າງ ເພື່ອນັບຈຳນວນຄຳ.")

    word_count = count_words_in_file("sample.txt")
    if word_count > 0:
