Absolutely! Here's a reusable TypeScript debounce function that's perfect for React or any JavaScript environment:

```typescript
function debounce<T extends (...args: any[]) => void>(
  func: T,
  delay: number
): (...args: Parameters<T>) => void {
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  return function(this: any, ...args: Parameters<T>) {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
    timeoutId = setTimeout(() => {
      func.apply(this, args);
      timeoutId = null;
    }, delay);
  };
}

// Example usage in React (or plain JS):
// const handleSearch = debounce((query: string) => {
//   console.log('Searching for:', query);
// }, 500);
// <input onChange={(e) => handleSearch(e.target.value)} />
```
It's generic for any function type. Let me know if you'd like to see it integrated into a React hook!

Here's a JavaScript function to validate a strong password based on your criteria:

```javascript
function isStrongPassword(password) {
  // At least 8 characters long
  if (password.length < 8) return false;
  // Contains at least one uppercase letter
  if (!/[A-Z]/.test(password)) return false;
  // Contains at least one lowercase letter
  if (!/[a-z]/.test(password)) return false;
  // Contains at least one number
  if (!/[0-9]/.test(password)) return false;

  return true;
}

// Example usage:
console.log(isStrongPassword("Password123")); // true
console.log(isStrongPassword("password"));    // false (no uppercase, no number)
console.log(isStrongPassword("P@ssword"));    // false (no number)
```
