```tsx
import React, { useState } from 'react';

type Props = {
  label?: string;
  initialChecked?: boolean;
  onChange?: (checked: boolean) => void;
};

export function ToggleSwitch({ label, initialChecked = false, onChange }: Props) {
  const [isChecked, setIsChecked] = useState(initialChecked);

  const handleChange = () => {
    const newState = !isChecked;
    setIsChecked(newState);
    onChange?.(newState);
  };

  return (
    <label style={{ display: 'inline-flex', alignItems: 'center', cursor: 'pointer' }}>
      {label && <span style={{ marginRight: '8px' }}>{label}</span>}
      <input
        type="checkbox"
        checked={isChecked}
        onChange={handleChange}
        style={{ display: 'none' }}
      />
      <span style={{
        display: 'inline-block', width: '40px', height: '20px', borderRadius: '10px',
        backgroundColor: isChecked ? '#4CAF50' : '#ccc', position: 'relative',
        transition: 'background-color 0.3s'
      }}>
        <span style={{
          display: 'block', width: '16px', height: '16px', borderRadius: '50%',
          backgroundColor: 'white', position: 'absolute', top: '2px', left: isChecked ? '22px' : '2px',
          transition: 'left 0.3s'
        }}></span>
      </span>
    </label>
  );
}
```
