Đây là cách bạn có thể tạo endpoint DELETE trong Express để xóa tài nguyên theo ID:

```javascript
const express = require('express');
const app = express();
const port = 3000;

let resources = [
  { id: 'a1', name: 'Resource A' },
  { id: 'b2', name: 'Resource B' }
];

app.delete('/resources/:id', (req, res) => {
  const resourceId = req.params.id;
  const initialLength = resources.length;
  resources = resources.filter(r => r.id !== resourceId);

  if (resources.length < initialLength) {
    res.status(200).send(`Tài nguyên với ID ${resourceId} đã được xóa.`);
  } else {
    res.status(404).send('Không tìm thấy tài nguyên để xóa.');
  }
});

app.listen(port, () => {
  console.log(`API đang chạy tại http://localhost:${port}`);
});
```
