Of course! Here's a basic `Toast` component for temporary notifications:

```tsx
import React, { useState, useEffect, PropsWithChildren } from 'react';

type ToastProps = PropsWithChildren<{ 
  message: string;
  duration?: number; // milliseconds
  onClose: () => void;
}>;

export const Toast: React.FC<ToastProps> = ({ message, duration = 3000, onClose }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onClose();
    }, duration);
    return () => clearTimeout(timer);
  }, [duration, onClose]);

  return (
    <div style={{
      position: 'fixed', bottom: '20px', left: '50%', transform: 'translateX(-50%)',
      backgroundColor: '#333', color: 'white', padding: '10px 20px',
      borderRadius: '5px', zIndex: 1000, opacity: 0.9
    }}>
      {message}
    </div>
  );
};
```
This component displays a message for a set duration, then calls `onClose`. You'd typically manage its visibility in a parent component. Would you like different styling options for success/error messages?

