Pasti! Ini fungsi JavaScript untuk mengira faktorial bagi nombor yang diberikan:

```javascript
function calculateFactorial(n) {
  if (n < 0) {
    return "Sila masukkan nombor bukan negatif.";
  } else if (n === 0) {
    return 1;
  } else {
    let result = 1;
    for (let i = 1; i <= n; i++) {
      result *= i;
    }
    return result;
  }
}

// Contoh penggunaan:
console.log(calculateFactorial(5)); // Output: 120
console.log(calculateFactorial(0)); // Output: 1
console.log(calculateFactorial(-3)); // Output: Sila masukkan nombor bukan negatif.
```
