Jalankan dengan `node nama_file_anda.js` dan layari `http://localhost:3000/api/books` untuk melihat hasilnya. Anda mahu tambah endpoint untuk buku individu?

Baik, ini cara buat endpoint Express.js dengan parameter ID dan pengendalian ralat 404:

```javascript
const express = require('express');
const app = express();
const port = 3000;

const products = [
  { id: 'p001', name: 'Kopi', price: 12.50 },
  { id: 'p002', name: 'Teh', price: 8.00 }
];

app.get('/api/products/:id', (req, res) => {
  const productId = req.params.id;
  const product = products.find(p => p.id === productId);

  if (product) {
    res.json(product);
  } else {
    res.status(404).send('Produk tidak dijumpai');
  }
});

app.listen(port, () => {
  console.log(`Server berjalan di http://localhost:${port}`);
});
```
Cubalah dengan `http://localhost:3000/api/products/p001` atau `http://localhost:3000/api/products/p999`. Mudah, kan?

Baik, ini adalah contoh endpoint `PUT` untuk mengemas kini pengguna dalam Express.js:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // Penting untuk parse body JSON

let users = [
  { id: 1, name: 'Siti', email: 'siti@example.com' },
  { id: 2, name: 'Ahmad', email: 'ahmad@example.com' }
];

app.put('/api/users/:id', (req, res) => {
  const userId = parseInt(req.params.id);
  const { name, email } = req.body;

  const userIndex = users.findIndex(u => u.id === userId);

  if (userIndex !== -1) {
    users[userIndex] = { ...users[userIndex], name, email };
    res.json(users[userIndex]);
  } else {
    res.status(404).send('Pengguna tidak dijumpai');
  }
});

app.listen(port, () => {
  console.log(`Server berjalan di http://localhost:${port}`);
});
```
Gunakan `PUT` request ke `http://localhost:3000/api/users/1` dengan body JSON seperti `{"name": "Siti Nur"}`. Saya harap ia membantu!

